                              ),
                          typedResults: items,
                        ),
                      if (receiptVouchersRefs)
                        await $_getPrefetchedData<
                          ShiftDb,
                          $ShiftsTable,
                          ReceiptVoucherDb
                        >(
                          currentTable: table,
                          referencedTable: $$ShiftsTableReferences
                              ._receiptVouchersRefsTable(db),
                          managerFromTypedResult: (p0) =>
