                                db,
                                table,
                                p0,
                              ).receiptVouchersRefs,
                          referencedItemsForCurrentItem:
                              (item, referencedItems) => referencedItems.where(
                                (e) => e.shiftLocalId == item.localId,
                              ),
                          typedResults: items,
                        ),
                      if (paymentVouchersRefs)
                        await $_getPrefetchedData<
                          ShiftDb,
